+    fn verify_rank1_monotonic(bitmap: &[u8], len: u32) {
+        let sb = SuccinctBitmap::build(bitmap, len);
+        let mut prev = 0_u32;
+        for i in 1..=len {
+            let r = sb.rank1(i);
+            assert!(
+                r >= prev,
+                "rank1({i}) = {r} < rank1({}) = {prev} (len={len})",
+                i - 1
+            );
+            assert!(
+                r <= prev + 1,
+                "rank1 jumped by more than 1 at position {i} (len={len}): {prev} -> {r}",
+            );
+            prev = r;
+        }
+        assert_eq!(
+            sb.rank1(len),
+            sb.count_ones(),
